 GF_Err gf_isom_write_compressed_box(GF_ISOFile *mov, GF_Box *root_box, u32 repl_type, GF_BitStream *bs, u32 *box_csize);

+static Bool gf_isom_trun_is_alive(GF_MovieFragmentBox *moof, GF_TrackFragmentRunBox *trun)
+{
+	/* Check whether the trun is still referenced from any TRAF TrackRuns list.
+	   Sometimes truns can be freed while their pointer remains in moof->trun_list;
+	   avoid dereferencing freed memory by verifying the trun is still present. */
+	u32 i = 0;
+	if (!moof || !trun) return GF_FALSE;
+	while (i < gf_list_count(moof->TrackList)) {
+		GF_TrackFragmentBox *traf = (GF_TrackFragmentBox*)gf_list_get(moof->TrackList, i);
+		if (traf) {
+			u32 j = 0;
+			while (j < gf_list_count(traf->TrackRuns)) {
+				GF_TrackFragmentRunBox *t = (GF_TrackFragmentRunBox*)gf_list_get(traf->TrackRuns, j);
+				if (t == trun) return GF_TRUE;
+				j++;
+			}
+		}
+		i++;
+	}
+	return GF_FALSE;
+}
+
 void flush_ref_samples(GF_ISOFile *movie, u64 *out_seg_size, Bool use_seg_marker)
 {
 	u32 i=0;
 	if (movie->in_sidx_write) return;
+	if (!movie->moof || !movie->moof->trun_list) return;
 	u32 trun_count = gf_list_count(movie->moof->trun_list);
 	for (i=0; i<trun_count; i++) {
 		GF_TrackFragmentRunBox *trun = gf_list_get(movie->moof->trun_list, i);
+		/* Ensure trun pointer is still valid and has sample_refs. If the trun was removed/freed,
+		   skip it to avoid dereferencing freed memory. */
+		if (!trun) continue;
+		if (!gf_isom_trun_is_alive(movie->moof, trun)) continue;
+		if (!trun->sample_refs) continue;
 		u32 s_count = gf_list_count(trun->sample_refs);
 		while (s_count) {
 			if (!use_seg_marker && movie->on_last_block_start && (i+1==trun_count) && (s_count==1)) {
 				movie->on_last_block_start(movie->on_block_out_usr_data);
 			}
 			GF_TrafSampleRef *sref = gf_list_pop_front(trun->sample_refs);
