diff --git a/test_ac3.c b/test_ac3.c
new file mode 100644
index 0000000..f6cf6dd
--- /dev/null
+++ b/test_ac3.c
@@ -0,0 +1,35 @@
+#include <stdio.h>
+#include <stdlib.h>
+#include <string.h>
+#include <limits.h>
+#include <stdint.h>
+
+// Simple test to check the logic
+int main() {
+    // Test case: remain=100, sync_pos=80, framesize=30
+    // Original check: remain >= framesize (100 >= 30) = true, but wrong!
+    // Our check: sync_pos <= remain (80 <= 100) && framesize <= remain - sync_pos (30 <= 20) = false!
+    
+    uint32_t remain = 100;
+    uint32_t sync_pos = 80;
+    uint32_t framesize = 30;
+    
+    printf("Test 1: remain=%u, sync_pos=%u, framesize=%u\n", remain, sync_pos, framesize);
+    printf("Original check (remain >= framesize): %s\n", remain >= framesize ? "PASS (wrong!)" : "FAIL");
+    printf("Our check (sync_pos <= remain && framesize <= remain - sync_pos): %s\n", 
+           (sync_pos <= remain) && (framesize <= remain - sync_pos) ? "PASS" : "FAIL (correct!)");
+    
+    // Test overflow case
+    remain = UINT_MAX - 100;
+    sync_pos = UINT_MAX - 50;
+    framesize = 100;
+    
+    printf("\nTest 2: overflow test\n");
+    printf("sync_pos + framesize would overflow: %u + %u = %u (overflow!)\n", 
+           sync_pos, framesize, sync_pos + framesize);
+    printf("Our check (sync_pos <= remain): %s\n", sync_pos <= remain ? "PASS" : "FAIL");
+    // Note: remain - sync_pos would underflow, but we check sync_pos > remain first
+    // In this case, sync_pos > remain (UINT_MAX-50 > UINT_MAX-100), so we would fail the first check
+    
+    return 0;
+}

